parameters.jsCode:
const b = $input.first().json.body;
if (!b.business || !b.offer) throw new Error('business and offer required');
return [{
  json: {
    job_id: b.job_id || null,
    business: b.business,
    offer: b.offer,
    target_audience: b.target_audience || 'local homeowners',
    platforms: b.platforms || ['facebook', 'instagram'],
    tone: b.tone || 'casual and trustworthy',
    cta: b.cta || 'Call now for a free quote',
    callback_url: b.callback_url || null
  }
}];

messages.content:
You are Aurora AI Agency's senior ad copywriter. Generate a complete social media ad package in JSON format.

Business: {{ $json.business }}
Offer: {{ $json.offer }}
Target audience: {{ $json.target_audience }}
Platforms: {{ $json.platforms.join(', ') }}
Tone: {{ $json.tone }}
CTA: {{ $json.cta }}

Return ONLY valid JSON with this exact structure:
{
  "facebook": {
    "primary_text": "(125 chars max, hook first)",
    "headline": "(40 chars max)",
    "description": "(25 chars max)",
    "variations": ["alt headline 1", "alt headline 2"]
  },
  "instagram": {
    "caption": "(150 chars with emoji, strong hook)",
    "hashtags": ["#tag1", "#tag2", "#tag3", "#tag4", "#tag5"],
    "story_text": "(short punchy text for Story overlay, max 80 chars)"
  },
  "google_rsa": {
    "headlines": ["h1 30chars", "h2 30chars", "h3 30chars"],
    "descriptions": ["d1 90chars", "d2 90chars"]
  },
  "notes": "brief copywriter notes on angle and why it works"
}

