const raw = $json.content[0].text.trim();
let ads;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  ads = JSON.parse(match ? match[0] : raw);
} catch (e) {
  ads = { raw_text: raw, parse_error: e.message };
}
const prev = $('parse-input').item.json;
return [{ json: { job_id: prev.job_id, business: prev.business, offer: prev.offer, platforms: prev.platforms, ads, callback_url: prev.callback_url, generated_at: new Date().toISOString() } }];
